
-- Drop existing tables
DROP TABLE IF EXISTS "Nilai";
DROP TABLE IF EXISTS "KRS";
DROP TABLE IF EXISTS "Matakuliah";
DROP TABLE IF EXISTS "Dosen";
DROP TABLE IF EXISTS "Mahasiswa";

-- Mahasiswa
CREATE TABLE "Mahasiswa" (
    "nim" VARCHAR PRIMARY KEY,
    "nama" VARCHAR,
    "jenis_kelamin" VARCHAR, 
    "prodi" VARCHAR, 
    "kelas" VARCHAR,  
    "angkatan" VARCHAR, 
    "status_aktif" VARCHAR, 
    "semester" INTEGER 
);

-- Dosen
CREATE TABLE "Dosen" (
    "kode_dosen" VARCHAR PRIMARY KEY,
    "nama" VARCHAR,
    "mata_kuliah" VARCHAR
);

-- Matakuliah
CREATE TABLE "Matakuliah" (
    "kode_matakuliah" VARCHAR PRIMARY KEY,
    "nama_matakuliah" VARCHAR,
    "sks" INTEGER,
    "prodi" VARCHAR,
    "kode_dosen" VARCHAR REFERENCES "Dosen"("kode_dosen"),
    "semester" INTEGER,
    "hari" VARCHAR,
    "jam_mulai" VARCHAR,
    "jam_selesai" VARCHAR,
    "ruangan" VARCHAR
);

-- KRS
CREATE TABLE "KRS" (
    "id" SERIAL PRIMARY KEY,
    "nim" VARCHAR REFERENCES "Mahasiswa"("nim"),
    "kode_matakuliah" VARCHAR REFERENCES "Matakuliah"("kode_matakuliah")
);

-- Nilai
CREATE TABLE "Nilai" (
    "id" SERIAL PRIMARY KEY,
    "nim" VARCHAR REFERENCES "Mahasiswa"("nim"),
    "kode_matakuliah" VARCHAR REFERENCES "Matakuliah"("kode_matakuliah"),
    "absensi" INTEGER,
    "tugas" INTEGER,
    "quiz" INTEGER,
    "uts" INTEGER,
    "uas" INTEGER,
    "nilai_akhir" DECIMAL,
    "grade" VARCHAR,
    "status" VARCHAR
);

